    Car car{ carMake, carYear, numDoors };
    Truck truck{ truckMake, truckYear, payloadTons };

    std::cout << "Car: " << car.getMake() << " (" << car.getYear()
              << "), " << car.getNumDoors() << " doors\n";
    std::cout << std::fixed << std::setprecision(1);
    std::cout << "Truck: " << truck.getMake() << " (" << truck.getYear()
